#!/bin/bash
set -e
F="Beme-Frontend/src"
echo "[1/4] Products.jsx with variants..."
echo "" | base64 -d > "$F/pages/admin/sections/Products.jsx"
echo "  done"
echo "[2/4] Analytics.jsx with line graphs + heatmap..."
echo "" | base64 -d > "$F/pages/admin/sections/Analytics.jsx"
echo "  done"
echo "[3/4] Fixing Account.jsx..."
echo "" | base64 -d > /tmp/fac.js
node /tmp/fac.js "$F/pages/Account.jsx"
rm -f /tmp/fac.js
echo "[4/4] AdminPanel theme toggle..."
echo "" | base64 -d > /tmp/fat.js
node /tmp/fat.js "$F/pages/admin/AdminPanel.jsx"
rm -f /tmp/fat.js
cd Beme-Frontend && git add . && git commit -m "Line charts + heatmap + variants + theme toggle + account cleanup" && git push
echo "Done!"